#include "main.h"
#include "FreeRTOS.h"
#include "queue.h"
#include "task.h"
#include "mppt_internal.h"
#include "mppt.h"
#include "hrtim.h"

extern QueueHandle_t adc_queue;
static float now_current_A = 0.0f, now_voltage_mV = 0.0f;

#define RC_ALPHA_DENO_1        0.85f
#define RC_ALPHA_DENO_2        0.10f
#define RC_ALPHA_DENO_3        0.05f

#define MPPT_DUTY_MIN          500U
#define MPPT_DUTY_MAX          54000U
#define MPPT_DUTY_INIT         0U
#define MPPT_DUTY_STEP         80U
#define MPPT_POWER_EPS_W       0.03f
#define MPPT_CTRL_UPDATE_DIV   8U
#define MPPT_TASK_STACK_WORDS  256U
#define MPPT_TASK_PRIORITY     9U

void pwm_set_duty(uint32_t pwm_duty) //占空比0-54400
{
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_E, HRTIM_COMPAREUNIT_3, (pwm_duty >> 1) + 1);
    hhrtim1.Instance->sTimerxRegs[TIMER_E].CMP1CxR = pwm_duty;
}

float get_voltage_value(uint8_t index)
{
    if(index == 0)
        return now_voltage_mV;
    if(index == 1)
        return now_current_A;

    return 0.0f;
}

static float last_last_voltage_mV = 0.0f;

static inline __attribute__((always_inline)) void adc_data_process(uint32_t *data_buf)
{
    float origin_voltage_sum = 0.0f, origin_current_sum = 0.0f;
    for(uint8_t i = 0; i < ADC_BUFFER_LENGTH / 2; i++)
    {
        origin_voltage_sum += data_buf[i] & 0x0FFF;
        origin_current_sum += data_buf[i] >> 16;
    }
    // origin_voltage_sum / 4095 * 3300 / 20(样本量) = adc引脚上的电压
    // * 20 = 运放输入电压(运放20分压)
    // * 1.0079(adc误差修正)
    float temp_voltage_mV = origin_voltage_sum * 3300.0f / 4095.0f / (float)(ADC_BUFFER_LENGTH / 2) * 20.0f *
                            1.0079f;

    now_current_A = origin_current_sum * 3300.0f / 4095.0f / (ADC_BUFFER_LENGTH / 2) * 2.0f / 1000.0f; //单位A

    //对均值进行二阶rc滤波
    temp_voltage_mV = RC_ALPHA_DENO_1 * temp_voltage_mV + RC_ALPHA_DENO_2 * now_voltage_mV +
                      RC_ALPHA_DENO_3 * last_last_voltage_mV;

    last_last_voltage_mV = now_voltage_mV;
    now_voltage_mV = temp_voltage_mV;
}

static inline uint32_t clamp_duty(int32_t duty)
{
    if(duty < (int32_t)MPPT_DUTY_MIN)
        return MPPT_DUTY_MIN;
    if(duty > (int32_t)MPPT_DUTY_MAX)
        return MPPT_DUTY_MAX;
    return (uint32_t)duty;
}

void mppt_routine(void *args)
{
    static uint32_t *buf_ptr;
    uint32_t duty = MPPT_DUTY_INIT;
    int8_t direction = 1;
    uint8_t update_div_cnt = 0;

    float prev_power_w = 0.0f;
    uint8_t initialized = 0;

    pwm_set_duty(duty);

    (void)args;
    while(1)
    {
        //1. 等待ADC数据
        if(xQueueReceive(adc_queue, &buf_ptr, portMAX_DELAY) == pdTRUE)
        {
            adc_data_process(buf_ptr);

            if(++update_div_cnt < MPPT_CTRL_UPDATE_DIV)
                continue;
            update_div_cnt = 0;

            // V(mV) * I(A) => mW
            float now_power_w = (now_voltage_mV * now_current_A) / 1000.0f;

            if(!initialized)
            {
                prev_power_w = now_power_w;
                initialized = 1;
                continue;
            }

            float d_power = now_power_w - prev_power_w;

            if(d_power < -MPPT_POWER_EPS_W)
                direction = -direction;

            duty = clamp_duty((int32_t)duty + direction * (int32_t)MPPT_DUTY_STEP);

            if((duty == MPPT_DUTY_MIN && direction < 0) || (duty == MPPT_DUTY_MAX && direction > 0))
                direction = -direction;

            pwm_set_duty(duty);
            prev_power_w = now_power_w;
        }
    }
}

void MPPT_init(void)
{
    xTaskCreate(mppt_routine, "MPPT", MPPT_TASK_STACK_WORDS, NULL, MPPT_TASK_PRIORITY, NULL);
}

#include "main.h"
#include "FreeRTOS.h"
#include "queue.h"
#include "task.h"
#include "mppt_internal.h"
#include "mppt.h"
#include "hrtim.h"

extern QueueHandle_t adc_queue;
static float now_current_A = 0.0f, now_voltage_mV = 0.0f;

#define RC_ALPHA_DENO_1        0.85f
#define RC_ALPHA_DENO_2        0.10f
#define RC_ALPHA_DENO_3        0.05f

#define MPPT_DUTY_MIN          500U
#define MPPT_DUTY_MAX          54000U
#define MPPT_DUTY_INIT         0U
#define MPPT_DUTY_STEP_MIN     20U
#define MPPT_DUTY_STEP_MID     80U
#define MPPT_DUTY_STEP_MAX     200U
/*
 * MPPT_POWER_EPS_W: 功率变化死区阈值(单位W)。
 * |dP| 小于该值时认为变化主要来自采样噪声，不触发方向反转。
 */
#define MPPT_POWER_EPS_W       0.03f
#define MPPT_DP_SMALL_W        0.10f
#define MPPT_DP_LARGE_W        0.50f
#define MPPT_CTRL_UPDATE_DIV   8U
#define MPPT_TASK_STACK_WORDS  256U
#define MPPT_TASK_PRIORITY     9U

void pwm_set_duty(uint32_t pwm_duty) //占空比0-54400
{
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_E, HRTIM_COMPAREUNIT_3, (pwm_duty >> 1) + 1);
    hhrtim1.Instance->sTimerxRegs[TIMER_E].CMP1CxR = pwm_duty;
}

float get_voltage_value(uint8_t index)
{
    if(index == 0)
        return now_voltage_mV;
    if(index == 1)
        return now_current_A;

    return 0.0f;
}

static float last_last_voltage_mV = 0.0f;

static inline __attribute__((always_inline)) void adc_data_process(uint32_t *data_buf)
{
    float origin_voltage_sum = 0.0f, origin_current_sum = 0.0f;
    for(uint8_t i = 0; i < ADC_BUFFER_LENGTH / 2; i++)
    {
        origin_voltage_sum += data_buf[i] & 0x0FFF;
        origin_current_sum += data_buf[i] >> 16;
    }
    // origin_voltage_sum / 4095 * 3300 / 20(样本量) = adc引脚上的电压
    // * 20 = 运放输入电压(运放20分压)
    // * 1.0079(adc误差修正)
    float temp_voltage_mV = origin_voltage_sum * 3300.0f / 4095.0f / (float)(ADC_BUFFER_LENGTH / 2) * 20.0f *
                            1.0079f;

    now_current_A = origin_current_sum * 3300.0f / 4095.0f / (ADC_BUFFER_LENGTH / 2) * 2.0f / 1000.0f; //单位A

    //对均值进行二阶rc滤波
    temp_voltage_mV = RC_ALPHA_DENO_1 * temp_voltage_mV + RC_ALPHA_DENO_2 * now_voltage_mV +
                      RC_ALPHA_DENO_3 * last_last_voltage_mV;

    last_last_voltage_mV = now_voltage_mV;
    now_voltage_mV = temp_voltage_mV;
}

static inline uint32_t clamp_duty(int32_t duty)
{
    if(duty < (int32_t)MPPT_DUTY_MIN)
        return MPPT_DUTY_MIN;
    if(duty > (int32_t)MPPT_DUTY_MAX)
        return MPPT_DUTY_MAX;
    return (uint32_t)duty;
}

static inline uint32_t mppt_step_by_dp(float abs_dp)
{
    if(abs_dp >= MPPT_DP_LARGE_W)
        return MPPT_DUTY_STEP_MAX;
    if(abs_dp >= MPPT_DP_SMALL_W)
        return MPPT_DUTY_STEP_MID;
    return MPPT_DUTY_STEP_MIN;
}

void mppt_routine(void *args)
{
    static uint32_t *buf_ptr;
    uint32_t duty = MPPT_DUTY_INIT;
    int8_t direction = 1;
    uint8_t update_div_cnt = 0;

    float prev_power_w = 0.0f;
    uint8_t initialized = 0;

    pwm_set_duty(duty);

    (void)args;
    while(1)
    {
        //1. 等待ADC数据
        if(xQueueReceive(adc_queue, &buf_ptr, portMAX_DELAY) == pdTRUE)
        {
            adc_data_process(buf_ptr);

            if(++update_div_cnt < MPPT_CTRL_UPDATE_DIV)
                continue;
            update_div_cnt = 0;

            // V(mV) * I(A) => mW
            float now_power_w = (now_voltage_mV * now_current_A) / 1000.0f;

            if(!initialized)
            {
                prev_power_w = now_power_w;
                initialized = 1;
                continue;
            }

            float d_power = now_power_w - prev_power_w;
            float abs_d_power = (d_power >= 0.0f) ? d_power : -d_power;
            uint32_t duty_step = mppt_step_by_dp(abs_d_power);

            if(d_power < -MPPT_POWER_EPS_W)
                direction = -direction;

            duty = clamp_duty((int32_t)duty + direction * (int32_t)duty_step);

            if((duty == MPPT_DUTY_MIN && direction < 0) || (duty == MPPT_DUTY_MAX && direction > 0))
                direction = -direction;

            pwm_set_duty(duty);
            prev_power_w = now_power_w;
        }
    }
}

void MPPT_init(void)
{
    xTaskCreate(mppt_routine, "MPPT", MPPT_TASK_STACK_WORDS, NULL, MPPT_TASK_PRIORITY, NULL);
}

#include "pid_ctrl_internal.h"
#include "FreeRTOS.h"
#include <math.h>
#include "hrtim.h"
#include "main.h"
#include "task.h"
#include "queue.h"
#include "kalman.h"
#include "PID.h"

#define SWITCH_DELAY_CYCLES 500
#define n (3.33333f)

typedef enum {
    SWITCH_STATE_IDLE = 0,
    SWITCH_STATE_SLEEP_TRANSITION
} mode_switch_state_t;

extern QueueHandle_t adc_queue;

static pid_ctrl_block_handle_t pid_handle = NULL;
QueueHandle_t pid_ctrl_queue_mA = NULL; //单位为mV
static float now_high_current_mA = 0.0f, now_high_voltage_mV = 0.0f;
static float now_low_current_mA = 0.0f, now_low_voltage_mV = 0.0f;
static uint16_t mode = MODE_SLEEP;
uint8_t submode = 0;

float get_pid_value(uint8_t index)
{
    if(index == 0)
        return now_high_voltage_mV;
    if(index == 1)
        return now_high_current_mA;
    if(index == 2)
        return now_low_voltage_mV;
    if(index == 3)
        return now_low_current_mA;

    return 0.0f;
}

// 把DMA块数据转换为电压/电流工程量，并做电压去噪
static void adc_data_process(uint32_t *data_buf)
{
    static kalman_1d_state_t kf_high_voltage;
    static kalman_1d_state_t kf_high_current;
    static kalman_1d_state_t kf_low_voltage;
    static kalman_1d_state_t kf_low_current;
    static uint8_t is_kf_initialized = 0;
    uint16_t len = ADC_BUFFER_LENGTH / 2;

    uint32_t v_sum[2] = {0}; //0为高侧, 1为低侧
    uint32_t i_sum[2] = {0};

    //低16位对应ADC1,差分采样电流, rank1对应高侧
    for(uint32_t i = 0; i < len; i += 2)
    {
        v_sum[0] += data_buf[i] >> 16 & 0x0FFF;
        i_sum[0] += data_buf[i] & 0x0FFF;
        v_sum[1] += data_buf[i + 1] >> 16 & 0x0FFF;
        i_sum[1] += data_buf[i + 1] & 0x0FFF;
    }

    // 计算平均值 (每个通道采样 len/2 次)
    float v_avg_high = (float)v_sum[0] / ((float)len / 2.0f);
    float v_avg_low = (float)v_sum[1] / ((float)len / 2.0f);
    float i_avg_high = (float)i_sum[0] / ((float)len / 2.0f);
    float i_avg_low = (float)i_sum[1] / ((float)len / 2.0f);

    float raw_high_voltage_mV = v_avg_high * (3000.0f / 4095.0f);
    float raw_high_current_A = i_avg_high * (3000.0f / 4095.0f);
    float raw_low_voltage_mV = v_avg_low * (3000.0f / 4095.0f);
    float raw_low_current_A = i_avg_low * (3000.0f / 4095.0f);

    // 使用第一次测量值作为初始状态可以加快滤波器的收敛速度
    if(!is_kf_initialized)
    {
        // Q越大，跟踪越快，滤波效果越弱；Q越小，系统越稳定，但存在滞后
        // R越大，滤波效果越强，认为传感器噪声大；R越小，越相信传感器测量值
        kalman_1d_init(&kf_high_voltage, raw_high_voltage_mV, 10.0f, 0.5f, 50.0f); // 电压Q=0.5, R=50
        kalman_1d_init(&kf_high_current, raw_high_current_A, 1.0f, 0.01f, 1.0f); // 电流Q=0.01, R=1.0
        kalman_1d_init(&kf_low_voltage, raw_low_voltage_mV, 10.0f, 0.5f, 50.0f); // 电压Q=0.5, R=50
        kalman_1d_init(&kf_low_current, raw_low_current_A, 1.0f, 0.01f, 1.0f); // 电流Q=0.01, R=1.0
        is_kf_initialized = 1;
    }

    now_high_voltage_mV = kalman_1d_update(&kf_high_voltage, raw_high_voltage_mV);
    now_high_current_mA = kalman_1d_update(&kf_high_current, raw_high_current_A);
    now_low_voltage_mV = kalman_1d_update(&kf_low_voltage, raw_low_voltage_mV);
    now_low_current_mA = kalman_1d_update(&kf_low_current, raw_low_current_A);
}

// ==========================================================
// 硬件参数与系统宏定义
// ==========================================================
#define HRTIM_CLK_HZ     5.44e9f  // 定时器主时钟: 170M * 32
#define FS_MAX           135000.0f      // 最高开关频率 (对应极轻载/空载)
#define FS_MIN           95000.0f       // 最低开关频率 (对应满载)
#define TRANSFORMER_N    3.0f           // 变压器匝比 3:1

#define SWITCH_DELAY_CYCLES 50          // 模式切换时在SLEEP模式停留的周期数

// 功率传输方向枚举
typedef enum {
    DIR_FORWARD = 0, // 正向: 10V~15V -> 3V~4.2V
    DIR_REVERSE = 1  // 反向: 3V~4.2V -> 10V~15V
} power_dir_t;

// 记录当前的周期计数值(全局静态变量，供移相函数同步使用)
static uint32_t current_period_ticks = PWM_Period; // 默认 100kHz

// 宏定义：开启和关闭全部8个桥臂的输出
#define HRTIM_ALL_OUTPUTS (HRTIM_OUTPUT_TA1 | HRTIM_OUTPUT_TA2 | \
                           HRTIM_OUTPUT_TB1 | HRTIM_OUTPUT_TB2 | \
                           HRTIM_OUTPUT_TC1 | HRTIM_OUTPUT_TC2 | \
                           HRTIM_OUTPUT_TD1 | HRTIM_OUTPUT_TD2)

void HRTIM_Update_Timing(float fs_hz, float alpha_p_rad, float alpha_s_rad, float theta_rad, power_dir_t dir)
{
    // 1. 频率限幅保护
    if(fs_hz > FS_MAX)
        fs_hz = FS_MAX;
    if(fs_hz < FS_MIN)
        fs_hz = FS_MIN;

    // 2. 根据新频率计算最新的周期 Ticks
    uint32_t new_period_ticks = (uint32_t)(HRTIM_CLK_HZ / fs_hz);
    uint32_t half_period = new_period_ticks / 2;

    // 3. 根据【最新的周期】，将弧度(rad)转换为 Ticks
    float rad_to_ticks = (float)new_period_ticks / (2.0f * 3.14159265f);

    uint32_t alpha_p_t = (uint32_t)(alpha_p_rad * rad_to_ticks);
    uint32_t alpha_s_t = (uint32_t)(alpha_s_rad * rad_to_ticks);
    uint32_t theta_t = (uint32_t)(theta_rad * rad_to_ticks);

    // 4. 计算 Master Timer 负责同步的四个移相重置点 (CMP)
    uint32_t cmp2;

    uint32_t cmp1 = 0; // Timer A (初级上桥) 永远为基准

    // Timer C (初级下桥) 滞后 A 180度 + alpha_p
    uint32_t cmp3 = (cmp1 + half_period + alpha_p_t) % new_period_ticks;

    // Timer B (次级上桥) 相对于 A 的偏移 theta
    if(dir == DIR_FORWARD)
    {
        cmp2 = (cmp1 + theta_t) % new_period_ticks;
    }
    else
    {
        // 反向：次级超前初级，相当于滞后 (Period - theta)
        cmp2 = (cmp1 + new_period_ticks - theta_t) % new_period_ticks;
    }

    // Timer D (次级下桥) 滞后 B 180度 + alpha_s
    uint32_t cmp4 = (cmp2 + half_period + alpha_s_t) % new_period_ticks;

    // --------------------------------------------------------
    // 5. 硬件极值约束保护
    // --------------------------------------------------------
    // Master CMP2 和 CMP4 最小不能低于 96 (硬件限制)
    if(cmp2 < 96)
        cmp2 = 96;
    if(cmp4 < 96)
        cmp4 = 96;

    // CMP 不能大于等于 Period，否则无法触发同步
    if(cmp2 >= new_period_ticks)
        cmp2 = new_period_ticks - 1;
    if(cmp3 >= new_period_ticks)
        cmp3 = new_period_ticks - 1;
    if(cmp4 >= new_period_ticks)
        cmp4 = new_period_ticks - 1;

    // --------------------------------------------------------
    // 6. 一次性将所有值写入 HRTIM 寄存器
    // (依赖 HRTIM 的 Preload 影子寄存器机制同步生效)
    // --------------------------------------------------------
    // 更新周期
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_MASTER, new_period_ticks);
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A, new_period_ticks);
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_TIMER_B, new_period_ticks);
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_TIMER_C, new_period_ticks);
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_TIMER_D, new_period_ticks);

    // 更新 A, B, C, D 的 50% 占空比翻转点
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A, HRTIM_COMPAREUNIT_3, half_period);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_B, HRTIM_COMPAREUNIT_3, half_period);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_C, HRTIM_COMPAREUNIT_3, half_period);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_D, HRTIM_COMPAREUNIT_3, half_period);

    // 更新 Master 的 4 个移相控制点
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_MASTER, HRTIM_COMPAREUNIT_1, cmp1);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_MASTER, HRTIM_COMPAREUNIT_2, cmp2);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_MASTER, HRTIM_COMPAREUNIT_3, cmp3);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_MASTER, HRTIM_COMPAREUNIT_4, cmp4);

    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_MASTER, 0);
    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A, 0);
    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_TIMER_B, 0);
    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_TIMER_C, 0);
    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_TIMER_D, 0);
}

static void PID_ctrl_routine(void *pvParameters)
{
    static uint16_t target_current_mA = 0;
    static uint16_t target_current_mA_buffer = 0;
    static uint32_t queue_recv_buffer = 0;

    static uint32_t mode_tick_count = 0;

    // PID 相关变量
    static float fs_output = FS_MAX; // 初始化为最高频率(最小功率输出)
    static float error_mA = 0.0f;

    static uint32_t *buf_ptr;

    // 模式安全切换使用的状态变量
    static mode_switch_state_t switch_state = SWITCH_STATE_IDLE;
    static uint16_t switch_timer = 0;
    static uint16_t target_mode_request = MODE_SLEEP;
    static uint8_t is_auto_mode = 0;
    static uint8_t submode = 0; // for storing the submode

    // 4-DOF 解算变量
    float alpha_p, alpha_s, theta_val;

    power_dir_t current_dir = DIR_FORWARD;

    while(1)
    {
        // 1. 等待ADC数据 (10kHz 或 20kHz 的控制率)
        if(xQueueReceive(adc_queue, &buf_ptr, portMAX_DELAY) == pdTRUE)
        {
            HAL_GPIO_TogglePin(GPIOC, GPIO_PIN_1); // 调试翻转引脚

            // 2. 查询 target 是否改变
            if(pdPASS == xQueueReceive(pid_ctrl_queue_mA, &queue_recv_buffer, 0))
            {
                uint16_t recv_mode = queue_recv_buffer >> 16;
                uint16_t recv_target = queue_recv_buffer & 0xFFFF;

                if (recv_mode == MODE_AUTO) {
                    is_auto_mode = 1;
                    target_current_mA_buffer = recv_target;
                } else {
                    is_auto_mode = 0;
                    if(mode != recv_mode && switch_state == SWITCH_STATE_IDLE)
                    {
                        target_mode_request = recv_mode;
                        target_current_mA_buffer = recv_target;

                        // 切入 SLEEP 模式进行死区时间的缓冲保护
                        mode = MODE_SLEEP;
                        switch_state = SWITCH_STATE_SLEEP_TRANSITION;
                        switch_timer = 0;
                        mode_tick_count = 0;

                        pid_reset_ctrl_block(pid_handle);
                        fs_output = FS_MAX; // 切换时频率重置为最安全状态
                    }
                    else if(switch_state == SWITCH_STATE_IDLE)
                    {
                        target_current_mA = recv_target; // 仅更新电流
                    }
                }
            }

            adc_data_process(buf_ptr);

            // 发挥部分二：处理自动模式方向切换
            if(is_auto_mode && switch_state == SWITCH_STATE_IDLE)
            {
                uint16_t auto_target_mode = mode; // 默认维持当前状态

                if(now_high_voltage_mV >= 11500)
                {
                    auto_target_mode = MODE_1TO2; // 电压偏高，充电给低压侧
                }
                else if(now_high_voltage_mV <= 11000)
                {
                    auto_target_mode = MODE_2TO1; // 电压偏低，低压侧放电给高压侧
                }

                if(mode != auto_target_mode)
                {
                    target_mode_request = auto_target_mode;
                    mode = MODE_SLEEP;
                    switch_state = SWITCH_STATE_SLEEP_TRANSITION;
                    switch_timer = 0;
                    mode_tick_count = 0;

                    pid_reset_ctrl_block(pid_handle);
                    fs_output = FS_MAX;
                }
                else
                {
                    target_current_mA = target_current_mA_buffer;
                }
            }

            // 3. 状态机处理模式切换
            if(switch_state == SWITCH_STATE_SLEEP_TRANSITION)
            {
                if(++switch_timer >= SWITCH_DELAY_CYCLES)
                {
                    mode = target_mode_request;
                    target_current_mA = target_current_mA_buffer;
                    switch_state = SWITCH_STATE_IDLE;
                    mode_tick_count = 0;
                    pid_reset_ctrl_block(pid_handle);
                }
            }

            // ==========================================================
            // 4. 4-DOF 无功消除解算 (核心算法)
            // ==========================================================
            // 限制高压侧输入防止除以 0
            float v_high = now_high_voltage_mV < 10.0f ? 10.0f : now_high_voltage_mV;
            float v_low = now_low_voltage_mV;

            // 计算当前的电压增益 M
            float M = TRANSFORMER_N * v_low / v_high;

            if(M <= 1.0f)
            {
                alpha_s = 0.0f;
                // 用 fmaxf 保证开方不为负数
                theta_val = asinf(sqrtf(fmaxf(0.0f, 1.0f - M)));
                alpha_p = theta_val;
            }
            else
            {
                alpha_p = 0.0f;
                theta_val = asinf(sqrtf(fmaxf(0.0f, 1.0f - 1.0f / M)));
                alpha_s = theta_val;
            }

            // ==========================================================
            // 5. 执行具体模式逻辑
            // ==========================================================
            switch(mode)
            {
                case MODE_SLEEP:
                    if(mode_tick_count == 0)
                    {
                        // 关断所有 8 个管子
                        HAL_HRTIM_WaveformOutputStop(&hhrtim1, HRTIM_ALL_OUTPUTS);
                        HRTIM_Update_Timing(FS_MAX, 0.0f, 0.0f, 0.0f, DIR_FORWARD); // 待机设为最高频
                        mode_tick_count++;
                    }
                    continue; // Sleep 下不进行 PID 计算

                case MODE_1TO2: // 正向充电
                    if(now_low_voltage_mV <= 3000)
                    {
                        submode = 1;
                        target_current_mA = 500; // 电池过放，使用 500mA 预充
                    }
                    else
                    {
                        submode = 2;
                        target_current_mA = target_current_mA_buffer;
                    }

                    // 正向：误差 = 目标电流 - 次级充电电流
                    error_mA = (float)target_current_mA - now_low_current_mA;
                    current_dir = DIR_FORWARD;

                    if(mode_tick_count == 0)
                    {
                        // 载入频率控制的PID参数 (负极性配置: 误差大 -> 频率降)
                        pid_ctrl_parameter_t new_param = {
                            .kp           = -10.0f,     // 响应比例(按需微调)
                            .ki           = -1.0f,      // 积分(按需微调)
                            .kd           = 0.0f,
                            .max_output   = FS_MAX,     // 限制上限
                            .min_output   = FS_MIN,     // 限制下限
                            .max_integral = 30000.0f,   // 积分抗饱和上限
                            .min_integral = -30000.0f,  // 积分抗饱和下限
                            .cal_type     = PID_CAL_TYPE_POSITIONAL, // 位置式PID
                        };
                        pid_update_parameters(pid_handle, &new_param);

                        // 开启所有 8 个管子
                        HAL_HRTIM_WaveformOutputStart(&hhrtim1, HRTIM_ALL_OUTPUTS);
                        mode_tick_count++;
                    }
                    break;

                case MODE_2TO1: // 反向放电
                    // 发挥部分一（1）：a,a'端口电压≤10.0V 时，��出预充电流 0.1A
                    if(now_high_voltage_mV <= 10000)
                    {
                        submode = 1;
                        target_current_mA = 100;
                    }
                    else
                    {
                        submode = 2;
                        target_current_mA = target_current_mA_buffer;
                    }

                    // 发挥部分一（2）：当 a,a'端口电压=15.0V 后，保持 15.0V 恒压输出
                    if(now_high_voltage_mV > 14900)
                    {
                        float cv_error = 15000.0f - now_high_voltage_mV;
                        if(cv_error < 0.0f) cv_error = 0.0f;
                        float cv_target_mA = cv_error * 2.0f; // 简单的电压误差折算到电流环
                        if(target_current_mA > cv_target_mA) {
                            target_current_mA = cv_target_mA;
                        }
                    }

                    // 反向放电时高压侧电流为负值，取绝对值作为反馈量
                    // 误差 = 目标电流 - |实际电流|
                    error_mA = (float)target_current_mA - fabsf(now_high_current_mA);
                    current_dir = DIR_REVERSE;

                    if(mode_tick_count == 0)
                    {
                        // 反向放电：误差符号约定与正向一致，使用相同的负极性PID参数
                        pid_ctrl_parameter_t new_param = {
                            .kp           = -10.0f,
                            .ki           = -1.0f,
                            .kd           = 0.0f,
                            .max_output   = FS_MAX,
                            .min_output   = FS_MIN,
                            .max_integral = 30000.0f,
                            .min_integral = -30000.0f,
                            .cal_type     = PID_CAL_TYPE_POSITIONAL,
                        };
                        pid_update_parameters(pid_handle, &new_param);

                        HAL_HRTIM_WaveformOutputStart(&hhrtim1, HRTIM_ALL_OUTPUTS);
                        mode_tick_count++;
                    }
                    break;

                case MODE_AUTO:
                default:
                    continue;
            }

            // ==========================================================
            // 6. 进行 PID 计算并更新频率
            // ==========================================================
            // 由于上面配置了负向 Kp，当 target > actual (error > 0) 时，
            // PID 会拉低输出 fs_output，从而让阻抗变小，电流爬升。
            pid_compute(pid_handle, error_mA, &fs_output);

            HRTIM_Update_Timing(fs_output, alpha_p, alpha_s, theta_val, current_dir);
            LOGI("PID", "%.2f", fs_output);
        }
    }
}

void pid_set_current(uint32_t mA)
{
    if(NULL != pid_ctrl_queue_mA)
        xQueueSend(pid_ctrl_queue_mA, &mA, portMAX_DELAY);
}

void pid_ctrl_init(void)
{
    pid_ctrl_config_t pid_cfg = {
        .init_param = {
            .kp           = -10.0f,
            .ki           = -1.0f,
            .kd           = 0.0f,
            .max_output   = FS_MAX,
            .min_output   = FS_MIN,
            .max_integral = 30000.0f,
            .min_integral = -30000.0f,
            .cal_type     = PID_CAL_TYPE_POSITIONAL,
        }
    };
    pid_new_control_block(&pid_cfg, &pid_handle);
    pid_ctrl_queue_mA = xQueueCreate(6, sizeof(uint32_t));
    xTaskCreate(PID_ctrl_routine, "PID", 2048, NULL, 15, NULL);
}

#include "pid_ctrl_internal.h"
#include "FreeRTOS.h"
#include <math.h>
#include "hrtim.h"
#include "main.h"
#include "task.h"
#include "queue.h"
#include "kalman.h"
#include "PID.h"

#define SWITCH_DELAY_CYCLES 500
#define n (3.33333f)

typedef enum {
    SWITCH_STATE_IDLE = 0,
    SWITCH_STATE_SLEEP_TRANSITION
} mode_switch_state_t;

extern QueueHandle_t adc_queue;

static pid_ctrl_block_handle_t pid_handle = NULL;
QueueHandle_t pid_ctrl_queue_mA = NULL; //单位为mV
static float now_high_current_mA = 0.0f, now_high_voltage_mV = 0.0f;
static float now_low_current_mA = 0.0f, now_low_voltage_mV = 0.0f;
static uint16_t mode = MODE_SLEEP;
uint8_t submode = 0;

float get_pid_value(uint8_t index)
{
    if(index == 0)
        return now_high_voltage_mV;
    if(index == 1)
        return now_high_current_mA;
    if(index == 2)
        return now_low_voltage_mV;
    if(index == 3)
        return now_low_current_mA;

    return 0.0f;
}

// 把DMA块数据转换为电压/电流工程量，并做电压去噪
static void adc_data_process(uint32_t *data_buf)
{
    static kalman_1d_state_t kf_high_voltage;
    static kalman_1d_state_t kf_high_current;
    static kalman_1d_state_t kf_low_voltage;
    static kalman_1d_state_t kf_low_current;
    static uint8_t is_kf_initialized = 0;
    uint16_t len = ADC_BUFFER_LENGTH / 2;

    uint32_t v_sum[2] = {0}; //0为高侧, 1为低侧
    uint32_t i_sum[2] = {0};

    //低16位对应ADC1,差分采样电流, rank1对应高侧
    for(uint32_t i = 0; i < len; i += 2)
    {
        v_sum[0] += data_buf[i] >> 16 & 0x0FFF;
        i_sum[0] += data_buf[i] & 0x0FFF;
        v_sum[1] += data_buf[i + 1] >> 16 & 0x0FFF;
        i_sum[1] += data_buf[i + 1] & 0x0FFF;
    }

    // 计算平均值 (每个通道采样 len/2 次)
    float v_avg_high = (float)v_sum[0] / ((float)len / 2.0f);
    float v_avg_low = (float)v_sum[1] / ((float)len / 2.0f);
    float i_avg_high = (float)i_sum[0] / ((float)len / 2.0f);
    float i_avg_low = (float)i_sum[1] / ((float)len / 2.0f);

    float raw_high_voltage_mV = v_avg_high * (3000.0f / 4095.0f);
    float raw_high_current_A = i_avg_high * (3000.0f / 4095.0f);
    float raw_low_voltage_mV = v_avg_low * (3000.0f / 4095.0f);
    float raw_low_current_A = i_avg_low * (3000.0f / 4095.0f);

    // 使用第一次测量值作为初始状态可以加快滤波器的收敛速度
    if(!is_kf_initialized)
    {
        // Q越大，跟踪越快，滤波效果越弱；Q越小，系统越稳定，但存在滞后
        // R越大，滤波效果越强，认为传感器噪声大；R越小，越相信传感器测量值
        kalman_1d_init(&kf_high_voltage, raw_high_voltage_mV, 10.0f, 0.5f, 50.0f); // 电压Q=0.5, R=50
        kalman_1d_init(&kf_high_current, raw_high_current_A, 1.0f, 0.01f, 1.0f); // 电流Q=0.01, R=1.0
        kalman_1d_init(&kf_low_voltage, raw_low_voltage_mV, 10.0f, 0.5f, 50.0f); // 电压Q=0.5, R=50
        kalman_1d_init(&kf_low_current, raw_low_current_A, 1.0f, 0.01f, 1.0f); // 电流Q=0.01, R=1.0
        is_kf_initialized = 1;
    }

    now_high_voltage_mV = kalman_1d_update(&kf_high_voltage, raw_high_voltage_mV);
    now_high_current_mA = kalman_1d_update(&kf_high_current, raw_high_current_A);
    now_low_voltage_mV = kalman_1d_update(&kf_low_voltage, raw_low_voltage_mV);
    now_low_current_mA = kalman_1d_update(&kf_low_current, raw_low_current_A);
}

// ==========================================================
// 硬件参数与系统宏定义
// ==========================================================
#define HRTIM_CLK_HZ     5.44e9f  // 定时器主时钟: 170M * 32
#define FS_MAX           135000.0f      // 最高开关频率 (对应极轻载/空载)
#define FS_MIN           95000.0f       // 最低开关频率 (对应满载)
#define TRANSFORMER_N    3.0f           // 变压器匝比 3:1

#define SWITCH_DELAY_CYCLES 50          // 模式切换时在SLEEP模式停留的周期数

// 功率传输方向枚举
typedef enum {
    DIR_FORWARD = 0, // 正向: 10V~15V -> 3V~4.2V
    DIR_REVERSE = 1  // 反向: 3V~4.2V -> 10V~15V
} power_dir_t;

// 记录当前的周期计数值(全局静态变量，供移相函数同步使用)
static uint32_t current_period_ticks = PWM_Period; // 默认 100kHz

// 宏定义：开启和关闭全部8个桥臂的输出
#define HRTIM_ALL_OUTPUTS (HRTIM_OUTPUT_TA1 | HRTIM_OUTPUT_TA2 | \
                           HRTIM_OUTPUT_TB1 | HRTIM_OUTPUT_TB2 | \
                           HRTIM_OUTPUT_TC1 | HRTIM_OUTPUT_TC2 | \
                           HRTIM_OUTPUT_TD1 | HRTIM_OUTPUT_TD2)

void HRTIM_Update_Timing(float fs_hz, float alpha_p_rad, float alpha_s_rad, float theta_rad, power_dir_t dir)
{
    // 1. 频率限幅保护
    if(fs_hz > FS_MAX)
        fs_hz = FS_MAX;
    if(fs_hz < FS_MIN)
        fs_hz = FS_MIN;

    // 2. 根据新频率计算最新的周期 Ticks
    uint32_t new_period_ticks = (uint32_t)(HRTIM_CLK_HZ / fs_hz);
    uint32_t half_period = new_period_ticks / 2;

    // 3. 根据【最新的周期】，将弧度(rad)转换为 Ticks
    float rad_to_ticks = (float)new_period_ticks / (2.0f * 3.14159265f);

    uint32_t alpha_p_t = (uint32_t)(alpha_p_rad * rad_to_ticks);
    uint32_t alpha_s_t = (uint32_t)(alpha_s_rad * rad_to_ticks);
    uint32_t theta_t = (uint32_t)(theta_rad * rad_to_ticks);

    // 4. 计算 Master Timer 负责同步的四个移相重置点 (CMP)
    uint32_t cmp2;

    uint32_t cmp1 = 0; // Timer A (初级上桥) 永远为基准

    // Timer C (初级下桥) 滞后 A 180度 + alpha_p
    uint32_t cmp3 = (cmp1 + half_period + alpha_p_t) % new_period_ticks;

    // Timer B (次级上桥) 相对于 A 的偏移 theta
    if(dir == DIR_FORWARD)
    {
        cmp2 = (cmp1 + theta_t) % new_period_ticks;
    }
    else
    {
        // 反向：次级超前初级，相当于滞后 (Period - theta)
        cmp2 = (cmp1 + new_period_ticks - theta_t) % new_period_ticks;
    }

    // Timer D (次级下桥) 滞后 B 180度 + alpha_s
    uint32_t cmp4 = (cmp2 + half_period + alpha_s_t) % new_period_ticks;

    // --------------------------------------------------------
    // 5. 硬件极值约束保护
    // --------------------------------------------------------
    // Master CMP2 和 CMP4 最小不能低于 96 (硬件限制)
    if(cmp2 < 96)
        cmp2 = 96;
    if(cmp4 < 96)
        cmp4 = 96;

    // CMP 不能大于等于 Period，否则无法触发同步
    if(cmp2 >= new_period_ticks)
        cmp2 = new_period_ticks - 1;
    if(cmp3 >= new_period_ticks)
        cmp3 = new_period_ticks - 1;
    if(cmp4 >= new_period_ticks)
        cmp4 = new_period_ticks - 1;

    // --------------------------------------------------------
    // 6. 一次性将所有值写入 HRTIM 寄存器
    // (依赖 HRTIM 的 Preload 影子寄存器机制同步生效)
    // --------------------------------------------------------
    // 更新周期
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_MASTER, new_period_ticks);
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A, new_period_ticks);
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_TIMER_B, new_period_ticks);
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_TIMER_C, new_period_ticks);
    __HAL_HRTIM_SETPERIOD(&hhrtim1, HRTIM_TIMERINDEX_TIMER_D, new_period_ticks);

    // 更新 A, B, C, D 的 50% 占空比翻转点
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A, HRTIM_COMPAREUNIT_3, half_period);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_B, HRTIM_COMPAREUNIT_3, half_period);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_C, HRTIM_COMPAREUNIT_3, half_period);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_D, HRTIM_COMPAREUNIT_3, half_period);

    // 更新 Master 的 4 个移相控制点
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_MASTER, HRTIM_COMPAREUNIT_1, cmp1);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_MASTER, HRTIM_COMPAREUNIT_2, cmp2);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_MASTER, HRTIM_COMPAREUNIT_3, cmp3);
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_MASTER, HRTIM_COMPAREUNIT_4, cmp4);

    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_MASTER, 0);
    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_TIMER_A, 0);
    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_TIMER_B, 0);
    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_TIMER_C, 0);
    // __HAL_HRTIM_SETCOUNTER(&hhrtim1, HRTIM_TIMERINDEX_TIMER_D, 0);
}

static void PID_ctrl_routine(void *pvParameters)
{
    static uint16_t target_current_mA = 0;
    static uint16_t target_current_mA_buffer = 0;
    static uint32_t queue_recv_buffer = 0;

    static uint32_t mode_tick_count = 0;

    // PID 相关变量
    static float fs_output = FS_MAX; // 初始化为最高频率(最小功率输出)
    static float error_mA = 0.0f;

    static uint32_t *buf_ptr;

    // 模式安全切换使用的状态变量
    static mode_switch_state_t switch_state = SWITCH_STATE_IDLE;
    static uint16_t switch_timer = 0;
    static uint16_t target_mode_request = MODE_SLEEP;
    static uint8_t is_auto_mode = 0;
    static uint8_t submode = 0; // for storing the submode

    // 4-DOF 解算变量
    float alpha_p, alpha_s, theta_val;

    power_dir_t current_dir = DIR_FORWARD;

    while(1)
    {
        // 1. 等待ADC数据 (10kHz 或 20kHz 的控制率)
        if(xQueueReceive(adc_queue, &buf_ptr, portMAX_DELAY) == pdTRUE)
        {
            HAL_GPIO_TogglePin(GPIOC, GPIO_PIN_1); // 调试翻转引脚

            // 2. 查询 target 是否改变
            if(pdPASS == xQueueReceive(pid_ctrl_queue_mA, &queue_recv_buffer, 0))
            {
                uint16_t recv_mode = queue_recv_buffer >> 16;
                uint16_t recv_target = queue_recv_buffer & 0xFFFF;

                if (recv_mode == MODE_AUTO) {
                    is_auto_mode = 1;
                    target_current_mA_buffer = recv_target;
                } else {
                    is_auto_mode = 0;
                    if(mode != recv_mode && switch_state == SWITCH_STATE_IDLE)
                    {
                        target_mode_request = recv_mode;
                        target_current_mA_buffer = recv_target;

                        // 切入 SLEEP 模式进行死区时间的缓冲保护
                        mode = MODE_SLEEP;
                        switch_state = SWITCH_STATE_SLEEP_TRANSITION;
                        switch_timer = 0;
                        mode_tick_count = 0;

                        pid_reset_ctrl_block(pid_handle);
                        fs_output = FS_MAX; // 切换时频率重置为最安全状态
                    }
                    else if(switch_state == SWITCH_STATE_IDLE)
                    {
                        target_current_mA = recv_target; // 仅更新电流
                    }
                }
            }

            adc_data_process(buf_ptr);

            // 发挥部分二：处理自动模式方向切换
            if(is_auto_mode && switch_state == SWITCH_STATE_IDLE)
            {
                uint16_t auto_target_mode = mode; // 默认维持当前状态

                if(now_high_voltage_mV >= 11500)
                {
                    auto_target_mode = MODE_1TO2; // 电压偏高，充电给低压侧
                }
                else if(now_high_voltage_mV <= 11000)
                {
                    auto_target_mode = MODE_2TO1; // 电压偏低，低压侧放电给高压侧
                }

                if(mode != auto_target_mode)
                {
                    target_mode_request = auto_target_mode;
                    mode = MODE_SLEEP;
                    switch_state = SWITCH_STATE_SLEEP_TRANSITION;
                    switch_timer = 0;
                    mode_tick_count = 0;

                    pid_reset_ctrl_block(pid_handle);
                    fs_output = FS_MAX;
                }
                else
                {
                    target_current_mA = target_current_mA_buffer;
                }
            }

            // 3. 状态机处理模式切换
            if(switch_state == SWITCH_STATE_SLEEP_TRANSITION)
            {
                if(++switch_timer >= SWITCH_DELAY_CYCLES)
                {
                    mode = target_mode_request;
                    target_current_mA = target_current_mA_buffer;
                    switch_state = SWITCH_STATE_IDLE;
                    mode_tick_count = 0;
                    pid_reset_ctrl_block(pid_handle);
                }
            }

            // ==========================================================
            // 4. 4-DOF 无功消除解算 (核心算法)
            // ==========================================================
            // 限制高压侧输入防止除以 0
            float v_high = now_high_voltage_mV < 10.0f ? 10.0f : now_high_voltage_mV;
            float v_low = now_low_voltage_mV;

            // 计算当前的电压增益 M
            float M = TRANSFORMER_N * v_low / v_high;

            if(M <= 1.0f)
            {
                alpha_s = 0.0f;
                // 用 fmaxf 保证开方不为负数
                theta_val = asinf(sqrtf(fmaxf(0.0f, 1.0f - M)));
                alpha_p = theta_val;
            }
            else
            {
                alpha_p = 0.0f;
                theta_val = asinf(sqrtf(fmaxf(0.0f, 1.0f - 1.0f / M)));
                alpha_s = theta_val;
            }

            // ==========================================================
            // 5. 执行具体模式逻辑
            // ==========================================================
            switch(mode)
            {
                case MODE_SLEEP:
                    if(mode_tick_count == 0)
                    {
                        // 关断所有 8 个管子
                        HAL_HRTIM_WaveformOutputStop(&hhrtim1, HRTIM_ALL_OUTPUTS);
                        HRTIM_Update_Timing(FS_MAX, 0.0f, 0.0f, 0.0f, DIR_FORWARD); // 待机设为最高频
                        mode_tick_count++;
                    }
                    continue; // Sleep 下不进行 PID 计算

                case MODE_1TO2: // 正向充电
                    if(now_low_voltage_mV <= 3000)
                    {
                        submode = 1;
                        target_current_mA = 500; // 电池过放，使用 500mA 预充
                    }
                    else
                    {
                        submode = 2;
                        target_current_mA = target_current_mA_buffer;
                    }

                    // 正向：误差 = 目标电流 - 次级充电电流
                    error_mA = (float)target_current_mA - now_low_current_mA;
                    current_dir = DIR_FORWARD;

                    if(mode_tick_count == 0)
                    {
                        // 载入频率控制的PID参数 (负极性配置: 误差大 -> 频率降)
                        pid_ctrl_parameter_t new_param = {
                            .kp           = -10.0f,     // 响应比例(按需微调)
                            .ki           = -1.0f,      // 积分(按需微调)
                            .kd           = 0.0f,
                            .max_output   = FS_MAX,     // 限制上限
                            .min_output   = FS_MIN,     // 限制下限
                            .max_integral = 30000.0f,   // 积分抗饱和上限
                            .min_integral = -30000.0f,  // 积分抗饱和下限
                            .cal_type     = PID_CAL_TYPE_POSITIONAL, // 位置式PID
                        };
                        pid_update_parameters(pid_handle, &new_param);

                        // 开启所有 8 个管子
                        HAL_HRTIM_WaveformOutputStart(&hhrtim1, HRTIM_ALL_OUTPUTS);
                        mode_tick_count++;
                    }
                    break;

                case MODE_2TO1: // 反向放电
                    // 发挥部分一（1）：a,a'端口电压≤10.0V 时，输出预充电流 0.1A
                    if(now_high_voltage_mV <= 10000)
                    {
                        submode = 1;
                        target_current_mA = 100;
                    }
                    else
                    {
                        submode = 2;
                        target_current_mA = target_current_mA_buffer;
                    }

                    // 发挥部分一（2）：当 a,a'端口电压=15.0V 后，保持 15.0V 恒压输出
                    if(now_high_voltage_mV > 14900)
                    {
                        float cv_error = 15000.0f - now_high_voltage_mV;
                        if(cv_error < 0.0f) cv_error = 0.0f;
                        float cv_target_mA = cv_error * 2.0f; // 简单的电压误差折算到电流环
                        if(target_current_mA > cv_target_mA) {
                            target_current_mA = cv_target_mA;
                        }
                    }

                    // 反向放电时高压侧电流为负值，取绝对值作为反馈量
                    // 误差 = 目标电流 - |实际电流|
                    error_mA = (float)target_current_mA - fabsf(now_high_current_mA);
                    current_dir = DIR_REVERSE;

                    if(mode_tick_count == 0)
                    {
                        // 反向放电：误差符号约定与正向一致，使用相同的负极性PID参数
                        pid_ctrl_parameter_t new_param = {
                            .kp           = -10.0f,
                            .ki           = -1.0f,
                            .kd           = 0.0f,
                            .max_output   = FS_MAX,
                            .min_output   = FS_MIN,
                            .max_integral = 30000.0f,
                            .min_integral = -30000.0f,
                            .cal_type     = PID_CAL_TYPE_POSITIONAL,
                        };
                        pid_update_parameters(pid_handle, &new_param);

                        HAL_HRTIM_WaveformOutputStart(&hhrtim1, HRTIM_ALL_OUTPUTS);
                        mode_tick_count++;
                    }
                    break;

                case MODE_AUTO:
                default:
                    continue;
            }

            // ==========================================================
            // 6. 进行 PID 计算并更新频率
            // ==========================================================
            // 由于上面配置了负向 Kp，当 target > actual (error > 0) 时，
            // PID 会拉低输出 fs_output，从而让阻抗变小，电流爬升。
            pid_compute(pid_handle, error_mA, &fs_output);

            HRTIM_Update_Timing(fs_output, alpha_p, alpha_s, theta_val, current_dir);
            LOGI("PID", "%.2f", fs_output);
        }
    }
}

void pid_set_current(uint32_t mA)
{
    if(NULL != pid_ctrl_queue_mA)
        xQueueSend(pid_ctrl_queue_mA, &mA, portMAX_DELAY);
}

void pid_ctrl_init(void)
{
    pid_ctrl_config_t pid_cfg = {
        .init_param = {
            .kp           = -10.0f,
            .ki           = -1.0f,
            .kd           = 0.0f,
            .max_output   = FS_MAX,
            .min_output   = FS_MIN,
            .max_integral = 30000.0f,
            .min_integral = -30000.0f,
            .cal_type     = PID_CAL_TYPE_POSITIONAL,
        }
    };
    pid_new_control_block(&pid_cfg, &pid_handle);
    pid_ctrl_queue_mA = xQueueCreate(6, sizeof(uint32_t));
    xTaskCreate(PID_ctrl_routine, "PID", 2048, NULL, 15, NULL);
}
